package integration_test

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
	"go.flipt.io/flipt/build/testing/integration"
	"go.flipt.io/flipt/rpc/flipt"
	rpcevaluation "go.flipt.io/flipt/rpc/flipt/evaluation"
	sdk "go.flipt.io/flipt/sdk/go"
	"google.golang.org/protobuf/encoding/protojson"
)

// TestBooleanFlagEvaluation tests successful evaluation of a boolean flag.
func TestBooleanFlagEvaluation(t *testing.T) {
	integration.Harness(t, func(t *testing.T, sdk sdk.SDK, opts integration.TestOpts) {
		ctx := context.Background()

		// Create a boolean flag
		flag, err := sdk.Flipt().CreateFlag(ctx, &flipt.CreateFlagRequest{
			NamespaceKey: opts.Namespace,
			Key:          "boolean-flag",
			Name:         "Boolean Flag",
			Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
			Enabled:      true,
		})
		require.NoError(t, err)
		assert.Equal(t, "boolean-flag", flag.Key)

		// Build the evaluation request
		evalReq := &rpcevaluation.EvaluationRequest{
			RequestId:    "test-request-1",
			NamespaceKey: opts.Namespace,
			FlagKey:      "boolean-flag",
			EntityId:     "user123",
			Context: map[string]string{
				"device": "mobile",
			},
		}

		// Marshal request to JSON
		reqBytes, err := protojson.Marshal(evalReq)
		require.NoError(t, err)

		// Make HTTP request to evaluate endpoint
		resp, err := http.Post(
			fmt.Sprintf("%s/evaluate/v1/boolean", opts.Addr),
			"application/json",
			bytes.NewReader(reqBytes),
		)
		require.NoError(t, err)
		defer resp.Body.Close()

		// Assert response status
		require.Equal(t, http.StatusOK, resp.StatusCode)

		// Read and unmarshal response
		respBody, err := io.ReadAll(resp.Body)
		require.NoError(t, err)

		var boolResp rpcevaluation.BooleanEvaluationResponse
		err = protojson.Unmarshal(respBody, &boolResp)
		require.NoError(t, err)

		// Verify response fields
		assert.Equal(t, "test-request-1", boolResp.RequestId)
		assert.Equal(t, "boolean-flag", boolResp.FlagKey)
		assert.True(t, boolResp.Enabled)
		assert.NotZero(t, boolResp.RequestDurationMillis)
	})
}

// TestVariantFlagEvaluation tests successful evaluation of a variant flag.
func TestVariantFlagEvaluation(t *testing.T) {
	integration.Harness(t, func(t *testing.T, sdk sdk.SDK, opts integration.TestOpts) {
		ctx := context.Background()

		// Create a variant flag
		flag, err := sdk.Flipt().CreateFlag(ctx, &flipt.CreateFlagRequest{
			NamespaceKey: opts.Namespace,
			Key:          "variant-flag",
			Name:         "Variant Flag",
			Type:         flipt.FlagType_VARIANT_FLAG_TYPE,
			Enabled:      true,
		})
		require.NoError(t, err)

		// Create variants
		variantA, err := sdk.Flipt().CreateVariant(ctx, &flipt.CreateVariantRequest{
			NamespaceKey: opts.Namespace,
			FlagKey:      "variant-flag",
			Key:          "variant-a",
			Name:         "Variant A",
