// TestNamespaceScoping tests that flags in different namespaces are isolated.
func TestNamespaceScoping(t *testing.T) {
	integration.Harness(t, func(t *testing.T, sdk sdk.SDK, opts integration.TestOpts) {
		ctx := context.Background()

		// Create a namespace-specific flag
		_, err := sdk.Flipt().CreateFlag(ctx, &flipt.CreateFlagRequest{
			NamespaceKey: opts.Namespace,
			Key:          "scoped-flag",
			Name:         "Scoped Flag",
			Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
			Enabled:      true,
		})
		require.NoError(t, err)

		// Create second namespace if not using default
		testNamespace := opts.Namespace
		if opts.Namespace == "default" {
			// Create a separate namespace
			ns, err := sdk.Flipt().CreateNamespace(ctx, &flipt.CreateNamespaceRequest{
				Key:  "other-namespace",
				Name: "Other Namespace",
			})
			require.NoError(t, err)
			testNamespace = ns.Key
		}

		// Evaluate the flag in the correct namespace
		evalReq := &rpcevaluation.EvaluationRequest{
			RequestId:    "scoped-req-1",
			NamespaceKey: opts.Namespace,
			FlagKey:      "scoped-flag",
			EntityId:     "scoped-user",
		}

		reqBytes, err := protojson.Marshal(evalReq)
		require.NoError(t, err)

		resp, err := http.Post(
			fmt.Sprintf("%s/evaluate/v1/boolean", opts.Addr),
			"application/json",
			bytes.NewReader(reqBytes),
		)
		require.NoError(t, err)
		defer resp.Body.Close()

		// Should succeed in the correct namespace
		require.Equal(t, http.StatusOK, resp.StatusCode)

		// Now try to evaluate the same flag from a different namespace
		evalReq2 := &rpcevaluation.EvaluationRequest{
			RequestId:    "scoped-req-2",
			NamespaceKey: testNamespace,
			FlagKey:      "scoped-flag",
			EntityId:     "scoped-user",
		}

		reqBytes2, err := protojson.Marshal(evalReq2)
		require.NoError(t, err)

		resp2, err := http.Post(
			fmt.Sprintf("%s/evaluate/v1/boolean", opts.Addr),
			"application/json",
			bytes.NewReader(reqBytes2),
		)
		require.NoError(t, err)
		defer resp2.Body.Close()

		// Should fail (flag doesn't exist in other namespace)
		assert.NotEqual(t, http.StatusOK, resp2.StatusCode)
	})
}

// TestEvaluationWithContext tests that context is passed through evaluation.
func TestEvaluationWithContext(t *testing.T) {
	integration.Harness(t, func(t *testing.T, sdk sdk.SDK, opts integration.TestOpts) {
		ctx := context.Background()

		// Create a variant flag with context-based rule
		flag, err := sdk.Flipt().CreateFlag(ctx, &flipt.CreateFlagRequest{
			NamespaceKey: opts.Namespace,
			Key:          "context-flag",
			Name:         "Context Flag",
			Type:         flipt.FlagType_VARIANT_FLAG_TYPE,
			Enabled:      true,
		})
		require.NoError(t, err)

		// Create variants
		variantA, err := sdk.Flipt().CreateVariant(ctx, &flipt.CreateVariantRequest{
			NamespaceKey: opts.Namespace,
			FlagKey:      flag.Key,
			Key:          "var-a",
			Name:         "Variant A",
		})
		require.NoError(t, err)

		// Create a segment with context constraint
		segment, err := sdk.Flipt().CreateSegment(ctx, &flipt.CreateSegmentRequest{
			NamespaceKey: opts.Namespace,
			Key:          "context-segment",
			Name:         "Context Segment",
			MatchType:    flipt.MatchType_ALL_MATCH_TYPE,
		})
		require.NoError(t, err)

		// Create a constraint that matches on context
		_, err = sdk.Flipt().CreateConstraint(ctx, &flipt.CreateConstraintRequest{
			NamespaceKey: opts.Namespace,
			SegmentKey:   segment.Key,
			Type:         flipt.ComparisonType_STRING_COMPARISON_TYPE,
			Property:     "environment",
			Operator:     "eq",
			Value:        "production",
		})
		require.NoError(t, err)

		// Create a rule for the segment
		rule, err := sdk.Flipt().CreateRule(ctx, &flipt.CreateRuleRequest{
			NamespaceKey: opts.Namespace,
			FlagKey:      flag.Key,
			SegmentKey:   segment.Key,
			Rank:         1,
		})
		require.NoError(t, err)

		// Create a distribution
		_, err = sdk.Flipt().CreateDistribution(ctx, &flipt.CreateDistributionRequest{
			NamespaceKey: opts.Namespace,
			FlagKey:      flag.Key,
			RuleId:       rule.Id,
			VariantId:    variantA.Id,
			Rollout:      100.0,
		})
		require.NoError(t, err)

		// Evaluate with matching context
		evalReq := &rpcevaluation.EvaluationRequest{
			RequestId:    "context-req",
			NamespaceKey: opts.Namespace,
			FlagKey:      flag.Key,
			EntityId:     "context-user",
			Context: map[string]string{
				"environment": "production",
			},
		}

		reqBytes, err := protojson.Marshal(evalReq)
		require.NoError(t, err)

		resp, err := http.Post(
			fmt.Sprintf("%s/evaluate/v1/variant", opts.Addr),
			"application/json",
			bytes.NewReader(reqBytes),
		)
		require.NoError(t, err)
		defer resp.Body.Close()

		require.Equal(t, http.StatusOK, resp.StatusCode)

		respBody, err := io.ReadAll(resp.Body)
		require.NoError(t, err)

		var variantResp rpcevaluation.VariantEvaluationResponse
		err = protojson.Unmarshal(respBody, &variantResp)
		require.NoError(t, err)

		// With matching context, should match
		assert.True(t, variantResp.Match)
		assert.Equal(t, "var-a", variantResp.VariantKey)
	})
}

