// TestBatchEvaluation tests batch evaluation of multiple flags.
func TestBatchEvaluation(t *testing.T) {
	integration.Harness(t, func(t *testing.T, sdk sdk.SDK, opts integration.TestOpts) {
		ctx := context.Background()

		// Create first boolean flag
		_, err := sdk.Flipt().CreateFlag(ctx, &flipt.CreateFlagRequest{
			NamespaceKey: opts.Namespace,
			Key:          "batch-bool-1",
			Name:         "Batch Boolean 1",
			Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
			Enabled:      true,
		})
		require.NoError(t, err)

		// Create second boolean flag
		_, err = sdk.Flipt().CreateFlag(ctx, &flipt.CreateFlagRequest{
			NamespaceKey: opts.Namespace,
			Key:          "batch-bool-2",
			Name:         "Batch Boolean 2",
			Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
			Enabled:      false,
		})
		require.NoError(t, err)

		// Build batch evaluation request
		batchReq := &rpcevaluation.BatchEvaluationRequest{
			RequestId: "batch-test-1",
			Requests: []*rpcevaluation.EvaluationRequest{
				{
					RequestId:    "req-1",
					NamespaceKey: opts.Namespace,
					FlagKey:      "batch-bool-1",
					EntityId:     "batch-user-1",
				},
				{
					RequestId:    "req-2",
					NamespaceKey: opts.Namespace,
					FlagKey:      "batch-bool-2",
					EntityId:     "batch-user-2",
				},
				{
					RequestId:    "req-3",
					NamespaceKey: opts.Namespace,
					FlagKey:      "non-existent-flag",
					EntityId:     "batch-user-3",
				},
			},
		}

		// Marshal request to JSON
		reqBytes, err := protojson.Marshal(batchReq)
		require.NoError(t, err)

		// Make HTTP request to batch endpoint
		resp, err := http.Post(
			fmt.Sprintf("%s/evaluate/v1/batch", opts.Addr),
			"application/json",
			bytes.NewReader(reqBytes),
		)
		require.NoError(t, err)
		defer resp.Body.Close()

		// Assert response status
		require.Equal(t, http.StatusOK, resp.StatusCode)

		// Read and unmarshal response
		respBody, err := io.ReadAll(resp.Body)
		require.NoError(t, err)

		var batchResp rpcevaluation.BatchEvaluationResponse
		err = protojson.Unmarshal(respBody, &batchResp)
		require.NoError(t, err)

		// Verify we got responses for all requests
		assert.Equal(t, 3, len(batchResp.Responses))

		// Verify first response (successful boolean evaluation)
		assert.Equal(t, rpcevaluation.EvaluationResponseType_BOOLEAN_EVALUATION_RESPONSE_TYPE, batchResp.Responses[0].Type)
		assert.NotNil(t, batchResp.Responses[0].GetBooleanResponse())
		assert.True(t, batchResp.Responses[0].GetBooleanResponse().Enabled)

		// Verify second response (boolean evaluation)
		assert.Equal(t, rpcevaluation.EvaluationResponseType_BOOLEAN_EVALUATION_RESPONSE_TYPE, batchResp.Responses[1].Type)
		assert.NotNil(t, batchResp.Responses[1].GetBooleanResponse())
		assert.False(t, batchResp.Responses[1].GetBooleanResponse().Enabled)

		// Verify third response (error response for missing flag)
		assert.Equal(t, rpcevaluation.EvaluationResponseType_ERROR_EVALUATION_RESPONSE_TYPE, batchResp.Responses[2].Type)
		assert.NotNil(t, batchResp.Responses[2].GetErrorResponse())
		assert.Equal(t, rpcevaluation.ErrorEvaluationReason_NOT_FOUND_ERROR_EVALUATION_REASON,
			batchResp.Responses[2].GetErrorResponse().Reason)
	})
}

// TestNamespaceScoping tests that flags in different namespaces are isolated.
func TestNamespaceScoping(t *testing.T) {
	integration.Harness(t, func(t *testing.T, sdk sdk.SDK, opts integration.TestOpts) {
		ctx := context.Background()

		// Create a namespace-specific flag
		_, err := sdk.Flipt().CreateFlag(ctx, &flipt.CreateFlagRequest{
			NamespaceKey: opts.Namespace,
			Key:          "scoped-flag",
			Name:         "Scoped Flag",
			Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
			Enabled:      true,
		})
		require.NoError(t, err)

		// Create second namespace if not using default
		testNamespace := opts.Namespace
		if opts.Namespace == "default" {
			// Create a separate namespace
			ns, err := sdk.Flipt().CreateNamespace(ctx, &flipt.CreateNamespaceRequest{
				Key:  "other-namespace",
				Name: "Other Namespace",
			})
			require.NoError(t, err)
			testNamespace = ns.Key
		}

		// Evaluate the flag in the correct namespace
		evalReq := &rpcevaluation.EvaluationRequest{
			RequestId:    "scoped-req-1",
			NamespaceKey: opts.Namespace,
			FlagKey:      "scoped-flag",
			EntityId:     "scoped-user",
